+unsigned char Autolidar::itohascii(unsigned char input)
+{
+  unsigned char ret = 0;
+
+  if(input < 10)
+  {
+    ret = input + '0';
+  }
+  else if(input < 16)
+  {
+    ret = input-10 + 'A';
+  }
+  else
+  {
+    ret = 255;
+    RCLCPP_INFO(this->get_logger(), "out of hex range");
+  }
+
+  return ret;
+}
